package com.rabitah.frontend.navigation;
import com.rabitah.frontend.AppContext; import com.rabitah.frontend.controller.*; import javafx.fxml.FXMLLoader; import javafx.scene.*; import javafx.stage.Stage; import java.io.IOException;
public final class SceneRouter {private final AppContext context;private Stage stage;public SceneRouter(AppContext context){this.context=context;}public void start(Stage stage){this.stage=stage;stage.setTitle("Rabitah");stage.setMinWidth(1024);stage.setMinHeight(700);showLogin();stage.show();}public void showLogin(){show("login.fxml",LoginController.class);}public void showShell(){show("shell.fxml",ShellController.class);}private void show(String name,Class<?> controllerType){try{FXMLLoader loader=new FXMLLoader(getClass().getResource("/com/rabitah/frontend/fxml/"+name));loader.setControllerFactory(type->{if(type==controllerType){if(type==LoginController.class)return new LoginController(context);if(type==ShellController.class)return new ShellController(context);}throw new IllegalArgumentException("Unsupported controller: "+type);});Scene scene=new Scene(loader.load(),1200,780);scene.getStylesheets().add(getClass().getResource("/com/rabitah/frontend/css/app.css").toExternalForm());stage.setScene(scene);}catch(IOException e){throw new IllegalStateException("Unable to load "+name,e);}}}
